package entity.hall;// 场次状态枚举（放在hall文件夹下，与Hall类关联）public enum SessionStatus {    NOT_STARTED("未开始"),  // 未到播放时间，可购票    ON_GOING("播放中"),     // 已开场，可购剩余座位    ENDED("已结束");        // 已散场，不可购票    private final String status;    // 构造方法：绑定中文描述    SessionStatus(String status) {        this.status = status;    }    // 获取状态描述（用于前端显示）    public String getStatus() {        return status;    }}